const item = $input.item.json;
let userMessage = item.userMessage || item.message || '';
const userContent = item.userContent || item.article || '';
const userEmail = item.email || item.email_to || 'user@example.com';
const sessionId = item.sessionId || item.session_id || 'session_' + Math.random().toString(36).substr(2, 9);
const conversationHistory = item.conversationHistory || [];

if (!userMessage || userMessage.trim() === '') {
  userMessage = "Summarize the attached content";
}
return [{ json: {
  userMessage,
  userContent,
  userEmail,
  sessionId,
  conversationHistory: Array.isArray(conversationHistory) ? conversationHistory.slice(-10) : [],
  timestamp: new Date().toISOString(),
  requestId: 'req_' + Date.now() + '_' + Math.floor(Math.random() * 1000000),
  retryCount: 0,
  maxRetries: 2
}}];

const current = $('Validate & Extract').first().json;
let memory = [];
let userProfile = {};

try {
  const raw = $input.first().json;
  if (Array.isArray(raw)) {
    memory = raw.slice(-10);
  } else if (raw && raw.error) {
    memory = [];
  }
} catch(e) {
  memory = [];
}

const pastTopics = memory.map(m => m.topic || '').filter(Boolean);
const pastTools = memory.map(m => m.tool_used || '').filter(Boolean);
userProfile = {
  knownTopics: [...new Set(pastTopics)].slice(-5),
  preferredTools: [...new Set(pastTools)].slice(-3),
  sessionCount: memory.length
};

const memoryContext = memory.length > 0
  ? memory.map(m => `[${m.created_at || 'past'}] User asked: "${m.user_message || ''}" → Agent used: ${m.tool_used || 'unknown'} → Summary: ${m.response_summary || ''}`).join('\n')
  : 'No prior memory for this session.';

return [{ json: {
  ...current,
  memory,
  memoryContext,
  userProfile,
  agentState: 'memory_loaded'
}}];

const data = $input.first().json;
const msg = data.userMessage.toLowerCase();
const hasContent = data.userContent && data.userContent.length > 0;

const needsSearch = msg.includes('latest') || msg.includes('current') || msg.includes('today') ||
  msg.includes('news') || msg.includes('price') || msg.includes('find') ||
  msg.includes('search') || msg.includes('who is') || msg.includes('what is');

const needsAnalysis = msg.includes('analyze') || msg.includes('compare') || msg.includes('research') ||
  msg.includes('trends') || msg.includes('insights');

const wordCount = data.userMessage.split(' ').length;
const complexity = wordCount > 80 ? 'high' : wordCount > 30 ? 'medium' : 'low';

const toolPlan = [];
if (needsSearch) toolPlan.push('web_search');
if (hasContent) toolPlan.push('content_processing');
if (needsAnalysis) toolPlan.push('deep_analysis');
toolPlan.push('llm_generation');
toolPlan.push('self_critique');

const executionPlan = {
  complexity,
  needsSearch,
  needsAnalysis,
  toolPlan,
  estimatedSteps: toolPlan.length,
  steps: toolPlan
};

return [{ json: {
  ...data,
  complexity,
  needsSearch,
  executionPlan,
  agentState: 'planning_complete'
}}];

