// 1. Grab data directly
const incomingItem = $input.item;
const planningData = $('Agentic Planning Layer').first().json;

try {
  const rawContent = incomingItem.json.choices?.[0]?.message?.content || "";
  const parsed = JSON.parse(rawContent);
  const target = (parsed.agent_target || 'general_assistant').toLowerCase().trim();

  return { json: {
    ...planningData,
    agent_target: target,
    needs_search: parsed.needs_search ?? planningData.needsSearch ?? false,
    search_query: parsed.search_query || planningData.userMessage,
    router_reasoning: parsed.reasoning || 'Direct processing'
  }};
} catch (error) {
  return { json: {
    ...planningData,
    agent_target: 'general_assistant',
    needs_search: false,
    search_query: planningData.userMessage,
    router_reasoning: `Fallback triggered: ${error.message}`
  }};
}

let searchResults = 'No web search was performed.';
let searchData = {};

try {
  const raw = $input.first().json;
  if (raw.organic_results && raw.organic_results.length > 0) {
    const top5 = raw.organic_results.slice(0, 5);
    searchResults = top5.map((r, i) =>
      `[${i+1}] ${r.title}\nSource: ${r.link}\nSnippet: ${r.snippet || 'N/A'}`
    ).join('\n\n');
    searchData = { resultsCount: top5.length, query: raw.search_parameters?.q || '' };
  } else if (raw.error) {
    searchResults = 'Web search unavailable: ' + raw.error;
  }
} catch(e) {
  searchResults = 'Web search parsing error: ' + e.message;
}

const decision = $('Parse Agent Decision').first().json;

return [{ json: {
  ...decision,
  searchResults,
  searchData,
  toolUsed: 'web_search',
  agentState: 'tools_executed'
}}];

const decision = $input.first().json;
return [{ json: {
  ...decision,
  searchResults: 'No web search performed for this request.',
  searchData: {},
  toolUsed: 'none',
  agentState: 'tools_executed'
}}];

