let agentOutput = '';
let agentName = 'General Assistant Agent';

try {
  const data = $('General Assistant Agent').first()?.json;

  // n8n AI Agent node always outputs to "output" key
  agentOutput = data?.choices?.[0]?.message?.content || data?.output || '';

  // Debug: if still empty, log what we actually got
  if (!agentOutput) {
    agentOutput = `DEBUG - Keys found: ${Object.keys(data || {}).join(', ')} | Raw: ${JSON.stringify(data).slice(0, 200)}`;
  }

} catch (e) {
  agentOutput = `Error: ${e.message}`;
}

const incoming = $input.first().json || {};

return [{
  json: {
    ...incoming,
    agentOutput,
    agentName
  }
}];

