const collectedData = $('Collect Agent Response').first().json;
let criticResult = { score: 10, passed: true, issues: [], improvement_instructions: '' };

try {
  const raw = $input.first().json;
  if (raw.choices && raw.choices[0]) {
    criticResult = JSON.parse(raw.choices[0].message.content);
  }
} catch(e) {
  criticResult = { score: 7, passed: true, issues: [], improvement_instructions: '' };
}

const currentRetry = collectedData.retryCount || 0;
const maxRetries = collectedData.maxRetries || 2;
const finalPassed = criticResult.passed || currentRetry >= maxRetries;

return [{ json: {
  ...collectedData,
  criticScore: criticResult.score || 7,
  criticPassed: finalPassed,
  criticIssues: criticResult.issues || [],
  improvementInstructions: criticResult.improvement_instructions || '',
  retryCount: currentRetry,
  maxRetries,
  agentState: finalPassed ? 'quality_passed' : 'quality_failed_retry'
}}];

// 1. Grab data directly from the node that just fed into this one
const data = $input.first().json;

// 2. Fallback logic with smart Error extraction
let agentOutput = 'No response generated.';

if (data.error && data.error.description) {
  agentOutput = `⚠️ AGENT API ERROR:\n${data.error.description}`;
} else {
  agentOutput = data.agentOutput || 
                data.text || 
                data.response || 
                data.output || 
                (data.choices && data.choices[0]?.message?.content) || 
                'No response generated.';
}

const agentName = data.agentName || (data.error ? 'System Error Monitor' : 'AI Agent');
const sessionId = data.sessionId || 'unknown';
const criticScore = data.error ? 0 : (data.criticScore || 10);
const retryCount = data.retryCount || 0;
const issues = data.criticIssues || [];
const toolUsed = data.toolUsed || 'none';
const searchUsed = toolUsed === 'web_search';

const userEmail = data.userEmail || data.email || 'user@example.com';
const userMessage = data.userMessage || '';
const requestId = data.requestId || '';
const routerReasoning = data.router_reasoning || '';

const qualityColor = data.error ? '#ef4444' : (criticScore >= 8 ? '#22c55e' : criticScore >= 6 ? '#f59e0b' : '#ef4444');
const qualityLabel = data.error ? 'Execution Failed' : (criticScore >= 8 ? 'High Quality' : criticScore >= 6 ? 'Acceptable' : 'Best Effort');

const responseSummary = agentOutput.slice(0, 300) + (agentOutput.length > 300 ? '...' : '');

const htmlEmail = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>AI Agent Response</title>
  <style>
    body{font-family:Arial,sans-serif;max-width:720px;margin:auto;padding:20px;line-height:1.7;}
    .header{background:linear-gradient(135deg,#1e293b 0%,#334155 100%);color:white;padding:28px 32px;border-radius:12px 12px 0 0;}
    .content{background:#f8fafc;padding:28px 32px;border-radius:0 0 12px 12px;}
    .meta-grid{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:20px;}
    .meta-card{background:white;border:1px solid #e2e8f0;border-radius:8px;padding:12px 16px;}
    .meta-label{font-size:11px;text-transform:uppercase;letter-spacing:.05em;color:#64748b;margin-bottom:4px;}
    .meta-value{font-size:14px;font-weight:600;color:#1e293b;}
    .quality-badge{display:inline-block;padding:4px 12px;border-radius:20px;font-size:12px;font-weight:600;background:${qualityColor}22;color:${qualityColor};border:1px solid ${qualityColor}44;}
    .tool-badge{display:inline-block;padding:4px 12px;border-radius:20px;font-size:12px;background:#6366f122;color:#6366f1;border:1px solid #6366f144;margin-left:6px;}
    .response-box{background:white;border:1px solid #e2e8f0;border-radius:10px;padding:24px;white-space:pre-wrap;font-size:14px;line-height:1.8;color:#334155;}
    .footer{margin-top:20px;font-size:11px;color:#94a3b8;border-top:1px solid #e2e8f0;padding-top:12px;}
  </style>
</head>
<body>
  <div class="header">
    <h1 style="margin:0 0 6px;font-size:22px;">Advanced AI Agent v2</h1>
    <p style="margin:0;opacity:.8;font-size:13px;">Full Agentic Response — Memory + Tools + Self-Correction</p>
  </div>
  <div class="content">
    <div class="meta-grid">
      <div class="meta-card"><div class="meta-label">Agent used</div><div class="meta-value">${agentName}</div></div>
      <div class="meta-card"><div class="meta-label">Status Check</div><div class="meta-value"><span class="quality-badge">${qualityLabel}</span></div></div>
      <div class="meta-card"><div class="meta-label">Tools used</div><div class="meta-value">${searchUsed ? '<span class="tool-badge">Web Search</span>' : 'Internal only'}</div></div>
      <div class="meta-card"><div class="meta-label">Self-corrections</div><div class="meta-value">${retryCount} of 2</div></div>
      <div class="meta-card"><div class="meta-label">Session ID</div><div class="meta-value" style="font-size:11px;">${sessionId}</div></div>
      <div class="meta-card"><div class="meta-label">Request ID</div><div class="meta-value" style="font-size:11px;">${requestId}</div></div>
    </div>
    ${issues.length > 0 ? '<div style="background:#fff7ed;border:1px solid #fed7aa;border-radius:8px;padding:12px 16px;margin-bottom:16px;font-size:13px;"><strong style="color:#c2410c;">Note:</strong> ' + issues.join('; ') + '</div>' : ''}
    <h2 style="font-size:16px;color:#1e293b;margin:0 0 12px;">Response Summary</h2>
    <div class="response-box" style="${data.error ? 'color:#ef4444; background:#fef2f2; border-color:#fca5a5;' : ''}">${agentOutput.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>')}</div>
    <div class="footer">Advanced AI Agent v2 | Groq Llama-3.3-70b | Memory: Supabase | Tools: SerpAPI<br>Router reasoning: ${routerReasoning}</div>
  </div>
</body>
</html>`;

const plainText = `ADVANCED AI AGENT v2 RESPONSE\n${'='.repeat(50)}\nAgent: ${agentName}\nStatus: ${qualityLabel}\n\nRESPONSE:\n${agentOutput}`;

return [{ json: {
  ...data,
  htmlEmail,
  plainText,
  emailSubject: `[AI Agent Status] · ${qualityLabel} · ${new Date().toLocaleDateString()}`,
  userEmail,
  responseSummary,
  agentOutput,
  agentName,
  toolUsed,
  criticScore,
  retryCount,
  agentState: 'email_ready'
}}];

const incoming = $input.first().json;

// Data comes nested inside "body" from webhook
const body = incoming.body || incoming;

return [{
  json: {
    ...incoming,
    userMessage:    body.userMessage    || '',
    userContent:    body.userContent    || '',
    searchResults:  body.searchResults  || '',
    memoryContext:  body.memoryContext  || '',
    sessionId:      body.sessionId      || `session_${Date.now()}`
  }
}];
